// 1) ElevenLabs 설정 — 회화 탭의 [목소리 설정]에서 입력 (이 기기에만 저장)
const VOICE_CFG = { apiKey: "", voiceId: "", autoPlay: true };
const ttsCache = new Map();
let currentAudio = null;
const stopAudio = () => {
  try { if (currentAudio) { currentAudio.pause(); currentAudio = null; } } catch (e) {}
  try { window.speechSynthesis && window.speechSynthesis.cancel(); } catch (e) {}
};

// 2) 브라우저 기본 목소리 (어린 소녀 톤) — ElevenLabs 미설정/실패 시 대비책
let titaVoice = null;
const pickTitaVoice = () => {
  try {
    const voices = window.speechSynthesis.getVoices() || [];
    const en = voices.filter((v) => v.lang && v.lang.toLowerCase().startsWith("en"));
    const us = en.filter((v) => v.lang.toLowerCase().includes("us"));
    const pool = us.length ? us : en;
    const find = (test) => pool.find((v) => test(v.name.toLowerCase()));
    titaVoice =
      find((n) => /\b(child|kid|girl|junior)\b/.test(n) || /\bana\b/.test(n)) ||
      find((n) => ["samantha", "zira", "jenny", "aria", "michelle", "salli", "joanna", "ivy", "female"].some((k) => n.includes(k))) ||
      find((n) => n.includes("google us english")) ||
      pool[0] || null;
  } catch (e) {}
};
try {
  if (window.speechSynthesis) {
    pickTitaVoice();
    window.speechSynthesis.onvoiceschanged = pickTitaVoice;
  }
} catch (e) {}

const speak = (text) => {
  try {
    if (!titaVoice) pickTitaVoice();
    const u = new SpeechSynthesisUtterance(text);
    u.lang = "en-US";
    if (titaVoice) u.voice = titaVoice;
    u.pitch = 1.35;
    u.rate = 0.95;
    window.speechSynthesis.cancel();
    window.speechSynthesis.speak(u);
  } catch (e) {}
};

// 3) 통합 재생: ElevenLabs 티타 보이스 우선, 안 되면 기본 목소리로 자동 전환
//    (같은 문장은 캐시에서 재생 → 글자 요금 아낌)
const titaSpeak = async (text) => {
  if (!text) return false;
  const { apiKey, voiceId } = VOICE_CFG;
  if (apiKey && voiceId) {
    try {
      let url = ttsCache.get(text);
      if (!url) {
        const res = await fetch(
          "https://api.elevenlabs.io/v1/text-to-speech/" + voiceId + "?output_format=mp3_44100_128",
          {
            method: "POST",
            headers: { "xi-api-key": apiKey, "Content-Type": "application/json" },
            body: JSON.stringify({
              text,
              model_id: "eleven_multilingual_v2",
              voice_settings: { stability: 0.5, similarity_boost: 0.75 },
            }),
          }
        );
        if (!res.ok) {
          let detail = "";
          try { detail = (await res.text()).slice(0, 200); } catch (e2) {}
          window.__titaErr = { status: res.status, detail };
          throw new Error("tts " + res.status);
        }
        const blob = await res.blob();
        url = URL.createObjectURL(blob);
        ttsCache.set(text, url);
      }
      window.__titaErr = null;
      stopAudio();
      const a = new Audio(url);
      currentAudio = a;
      await a.play();
      return true;
    } catch (e) {
      if (!window.__titaErr) window.__titaErr = { status: 0, detail: String(e && e.message || e) };
      /* 아래 기본 목소리로 폴백 */
    }
  }
  speak(text);
  return false;
};

// 4) 업로드해 둔 티타 보이스 샘플 미리듣기
const playSample = () => {
  try {
    stopAudio();
    const a = new Audio(TITA_VOICE_SAMPLE);
    currentAudio = a;
    a.play().catch(() => {});
  } catch (e) {}
};

